SELECT COUNT(DISTINCT user_id) AS number_of_users
FROM memory_access_logs
WHERE config_id = 1;

SELECT COUNT(*) AS num_regions
FROM memory_regions
WHERE peripheral_name = 'UART';

SELECT DISTINCT mc.region_id
FROM memory_configurations mc
ORDER BY mc.region_id;

SELECT memory_type, COUNT(*) AS memory_region_count
FROM memory_regions
GROUP BY memory_type;
